#include <stdio.h>
int countLuckyPairs(int N) {
    int count = 0;
    for (int L = 1; L <= N; L++) {
        for (int R = L; R <= N; R++) {
            int sum4 = 0, sum7 = 0;
            for (int i = L; i <= R; i++) {
                int num = i;
                while (num > 0) {
                    if (num % 10 == 4) sum4++;
                    if (num % 10 == 7) sum7++;
                    num /= 10;
                }
            }
            if (sum4 == sum7) count++;
        }
    }
    return count;
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        printf("%d\n", countLuckyPairs(N));
    }
    return 0;
}

